'use strict';
// ─────────────────────────────────────────────────────────────────────────────
// VENDORED VERBATIM from flatratenexus-project/app/services/citationFallback.js.
// DO NOT HAND-EDIT — re-vendor by copying the FRN source (a plain file copy, no
// transform; this module is pure Node `https`, no companion data files). Feature B
// (Citation Enricher, 2026-06-24) consumes retrieveGroundedAnchors() at PROPOSE time
// and verifyPmidById() for the apply-time SERVER-SIDE re-verify. The anti-fabrication
// invariants below are the safety keystone — every PMID comes from NCBI, the
// killer_finding is a verbatim abstract substring, retractions are rejected, and the
// module NEVER throws. Loaded at runtime via createRequire from the anchor-vendor tree
// (api-stack copies backend/src/vendor → <task>/anchor-vendor), exactly like
// anchorMechanism.cjs / eventCanon.cjs. Keyless NCBI is acceptable (3 req/s); reads
// process.env.NCBI_API_KEY || '' so a key can be added later without a code change.
// ─────────────────────────────────────────────────────────────────────────────
// citationFallback.js — GROUNDED on-the-fly citation retrieval for conditions with
// no curated library folder. The pipeline must ALWAYS be able to draft (no dead-stop);
// this fetches real A1 (institutional) / A2 (epi) / A3 (mechanism) anchors directly from
// NCBI PubMed E-utilities so the drafter has verified citations to work from.
//
// FAILSAFE / ANTI-FABRICATION INVARIANTS (do not weaken):
//   1. Every PMID is RETURNED BY NCBI (esearch), never generated by a model.
//   2. Every citation's metadata (title/journal/year/authors) comes from esummary.
//   3. The "killer finding" is a VERBATIM SUBSTRING of the efetch abstract — extracted,
//      never paraphrased. A citation with no extractable abstract sentence is REJECTED.
//   4. On-topic gate: the claimed-condition tokens must appear in the title+abstract.
//   5. Retracted publications are rejected.
//   6. This module NEVER throws to its caller — all network/parse errors are caught and
//      surfaced in the returned `trace`. A failure yields fewer anchors, never a crash.
//
// Created 2026-06-02 (Ryan: "PERFECT and FAILSAFE" fallback drafter; no librarian feature,
// just log when it fires). Used by app/scripts/step0-index-consult.js.

const https = require('https');

const EUTILS = 'https://eutils.ncbi.nlm.nih.gov/entrez/eutils';
// NCBI_API_KEY is read PER-REQUEST (apiKey() below), not frozen at module load, so a task-def env
// entry added after this module is required still takes effect. The key raises the rate limit
// 3/s -> 10/s and improves reliability (fewer 429s). Keyless still works. (Spring Bug 3, 2026-06-25.)
function apiKey() { return process.env.NCBI_API_KEY || ''; }
function throttleMs() { return apiKey() ? 110 : 350; } // stay under NCBI rate limit (keyed=10/s, keyless=3/s)
const REQ_TIMEOUT_MS = 12000;                   // raised 9s->12s: NCBI efetch is occasionally slow (Spring Bug 3)
const MAX_RETRIES = 3;                           // raised 2->3: backoff handles transient 429/timeout (Spring Bug 3)
const CANDIDATES_PER_SLOT = 6;                  // esearch breadth before giving up on a slot
const CANDIDATES_PER_SLOT_A3 = 10;              // A3 mechanism recall is harder — search wider (C2.iv)

// Slot query builders. Each ANDs the condition with slot-specific evidence terms and
// restricts to human English. esearch handles MeSH expansion server-side.
const SLOT = {
  A1: { label: 'INSTITUTIONAL', terms: '(guideline[Title/Abstract] OR consensus[Title/Abstract] OR "practice guideline"[Publication Type] OR recommendations[Title/Abstract] OR "clinical practice")' },
  A2: { label: 'EPI',           terms: '(cohort[Title/Abstract] OR prevalence[Title/Abstract] OR incidence[Title/Abstract] OR "odds ratio"[Title/Abstract] OR "relative risk"[Title/Abstract] OR meta-analysis[Publication Type] OR "risk factor"[Title/Abstract])' },
  A3: { label: 'MECHANISM',     terms: '(pathophysiology[Title/Abstract] OR mechanism[Title/Abstract] OR pathogenesis[Title/Abstract])' },
};

// Per-slot esearch breadth — A3 mechanism is recall-limited, so search wider (C2.iv).
function slotRetmax(slotName) { return slotName === 'A3' ? CANDIDATES_PER_SLOT_A3 : CANDIDATES_PER_SLOT; }

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

// ── HTTP with timeout + retry. Resolves to body string, or throws after retries. ──
// On a non-2xx, the thrown Error carries .statusCode and .retryAfterMs so eutil() can do
// rate-limit-aware backoff (NCBI returns 429 when the per-key/IP rate is exceeded). (Spring Bug 3.)
function httpGet(url) {
  return new Promise((resolve, reject) => {
    const req = https.get(url, (res) => {
      if (res.statusCode && (res.statusCode < 200 || res.statusCode >= 300)) {
        res.resume();
        const err = new Error(`HTTP ${res.statusCode}`);
        err.statusCode = res.statusCode;
        const ra = res.headers && res.headers['retry-after'];
        if (ra) { const secs = parseInt(ra, 10); if (!Number.isNaN(secs)) err.retryAfterMs = secs * 1000; }
        return reject(err);
      }
      let body = '';
      res.setEncoding('utf8');
      res.on('data', (d) => { body += d; });
      res.on('end', () => resolve(body));
    });
    req.setTimeout(REQ_TIMEOUT_MS, () => { req.destroy(new Error('timeout')); });
    req.on('error', reject);
  });
}

async function eutil(endpoint, params) {
  const key = apiKey();
  const qp = new URLSearchParams({ ...params, ...(key ? { api_key: key } : {}) });
  const url = `${EUTILS}/${endpoint}?${qp.toString()}`;
  const base = throttleMs();
  let lastErr;
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      // Exponential backoff on retry; on a 429 honor the server's Retry-After if longer. (Spring Bug 3.)
      let wait = base * (attempt + 1);
      if (attempt > 0 && lastErr) {
        wait = base * Math.pow(2, attempt);
        if (lastErr.statusCode === 429 && lastErr.retryAfterMs) wait = Math.max(wait, lastErr.retryAfterMs);
      }
      await sleep(wait);
      return await httpGet(url);
    } catch (e) { lastErr = e; }
  }
  throw lastErr || new Error('eutil failed');
}

async function esearch(term, retmax = CANDIDATES_PER_SLOT) {
  const body = await eutil('esearch.fcgi', {
    db: 'pubmed', term: `(${term}) AND humans[MeSH] AND English[lang]`,
    retmax: String(retmax), retmode: 'json', sort: 'relevance',
  });
  const j = JSON.parse(body);
  return (j.esearchresult && j.esearchresult.idlist) ? j.esearchresult.idlist : [];
}

async function esummaryBatch(pmids) {
  if (!pmids.length) return {};
  const body = await eutil('esummary.fcgi', { db: 'pubmed', id: pmids.join(','), retmode: 'json' });
  const j = JSON.parse(body);
  return (j.result) ? j.result : {};
}

async function efetchAbstractXml(pmid) {
  return eutil('efetch.fcgi', { db: 'pubmed', id: String(pmid), rettype: 'abstract', retmode: 'xml' });
}

// ── parsing / validation helpers ──
function decodeEntities(s) {
  return String(s).replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"').replace(/&apos;/g, "'").replace(/&#(\d+);/g, (_, n) => String.fromCharCode(+n));
}
function stripTags(s) { return decodeEntities(String(s).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim()); }

function parseAbstractXml(xml) {
  const isRetracted = /Retracted Publication<\/PublicationType>/i.test(xml) || /RetractionIn/i.test(xml);
  const parts = [...xml.matchAll(/<AbstractText[^>]*>([\s\S]*?)<\/AbstractText>/gi)].map((m) => stripTags(m[1]));
  const abstract = parts.join(' ').replace(/\s+/g, ' ').trim();
  return { abstract, isRetracted };
}

// Fold diacritics + lowercase so "Ménière" matches "meniere" (audit 2026-06-02 found accent
// false-negatives demoting good papers like the Ménière clinical-practice guideline).
function fold(s) { return String(s).normalize('NFD').replace(/[̀-ͯ]/g, '').toLowerCase(); }

// Generic disease-noise words that are never the CORE disease term. Strip these to find
// the core (e.g. "acne vulgaris with residual scarring" -> core "acne").
const NOISE_TOKENS = new Set([
  'with','from','disease','disorder','chronic','syndrome','secondary','residual','residuals',
  'condition','due','and','the','vulgaris','severe','mild','moderate','bilateral','unspecified',
  'scarring','recurrent','acute','status','post','left','right','type',
]);

function condTokens(condition) {
  return fold(condition).replace(/[^a-z0-9 ]/g, ' ').split(/\s+/)
    .filter((w) => w.length >= 4 && !NOISE_TOKENS.has(w));
}

// normalizeCondition(label) -> { core, synonyms[] } (C2.i)
// Extracts the CORE disease term from a verbose clinical label so the on-topic gate can
// match on the disease itself, not multi-word label fragments like "acne mechanica" or
// "chloracne" that rarely co-occur as a phrase in an abstract. The core is the FIRST
// non-noise token of length >= 4 (clinical labels lead with the disease name); synonyms
// are the remaining non-noise tokens (still useful as soft signal). Deterministic; never
// throws. A label with no usable token yields { core: '', synonyms: [] } (gate then accepts,
// matching the prior token-less behavior).
function normalizeCondition(label) {
  const toks = condTokens(label || '');
  if (!toks.length) return { core: '', synonyms: [] };
  return { core: toks[0], synonyms: toks.slice(1) };
}

// On-topic gate (C2.ii) — RELAXED for recall while staying grounded. The disease CORE term
// must appear in the title OR the abstract. (Previously required >=2 distinct label tokens,
// which whiffed multi-word labels: "acne mechanica" papers titled just "acne" failed the
// 2-token bar.) Still a hard disease match — an off-disease paper has no core token and is
// rejected. A token-less condition can't be gated, so it is accepted (and logged upstream).
function isOnTopic(condition, title, abstract) {
  const { core } = normalizeCondition(condition);
  if (!core) {
    // Fall back to the legacy multi-token gate only when there is no extractable core.
    const toks = condTokens(condition);
    if (!toks.length) return true;
    const hay0 = fold(`${title} ${abstract}`);
    return toks.filter((t) => hay0.includes(t)).length >= Math.min(2, toks.length);
  }
  const hay = fold(`${title} ${abstract}`);
  return hay.includes(core); // core disease term in title OR abstract = on-topic
}
// Title-match is a strong PRECISION signal for appropriateness (audit 2026-06-02: ~100% of
// title-match papers were appropriate anchors). Used as a soft RANKING preference, never a hard
// filter — ~20-30% of non-title papers are still good (broad guidelines, anatomy-named mechanism).
function titleMatches(condition, title) {
  const toks = condTokens(condition);
  if (!toks.length) return false;
  const t = fold(title);
  return toks.some((k) => t.includes(k));
}

// Methods/boilerplate sentences that are real abstract text but useless as a killer finding.
const BOILERPLATE = /(medline|embase|cinahl|cochrane|pubmed|scopus|prospero|prisma|databases?\b|search (strategy|terms|was|were)|literature search|were searched|inclusion criteri|exclusion criteri|registration|registered|this (review|study|article) (aims|reviews|summari)|we (aimed|sought|conducted a search|performed a search)|risk of bias)/i;
// A real quantified finding: %, effect estimate, CI, n=, fold/times, per-N, P-value, prevalence-with-number.
const QUANT = /(\d+(\.\d+)?\s?%|\b(aOR|aHR|OR|RR|HR)\b\s?[:=]?\s?\d|95\s?%\s?CI|\bCI\b\s?[:=]?\s?\d|\bn\s?=\s?\d|\d+(\.\d+)?[-–\s]?fold|\d+\s?times (more|higher|greater|the)|per\s?\d{2,}|\bP\s?[<=]\s?0?\.\d)/;

// Pick a VERBATIM abstract sentence as the killer finding: prefer a substantive CONCLUSIONS
// sentence, then a quantified finding, then the longest non-boilerplate sentence. Never a
// methods/database sentence. Returns '' if nothing usable (caller rejects the citation).
function extractKiller(abstract) {
  if (!abstract) return '';
  const sentences = (abstract.match(/[^.!?]+[.!?]/g) || [abstract]).map((s) => s.trim())
    .filter((s) => s.length >= 45 && s.length <= 600 && !BOILERPLATE.test(s));
  if (!sentences.length) return '';
  const concl = sentences.find((s) => /^(CONCLUSION|INTERPRETATION|FINDINGS|RESULTS)/i.test(s) && QUANT.test(s))
    || sentences.find((s) => /^(CONCLUSION|INTERPRETATION|FINDINGS)/i.test(s));
  if (concl) return concl;
  const quant = sentences.find((s) => QUANT.test(s));
  if (quant) return quant;
  return sentences.sort((a, b) => b.length - a.length)[0];
}

function buildCitation(sum) {
  const authors = (sum.authors || []).map((a) => a.name).filter(Boolean);
  let who = authors.length ? authors.slice(0, 3).join(', ') + (authors.length > 3 ? ', et al.' : '') : (sum.sortfirstauthor || 'Anonymous');
  const year = (sum.pubdate || '').match(/\d{4}/);
  const title = (sum.title || '').replace(/\.+$/, '');
  return `${who}. ${title}. ${sum.source || ''}. ${year ? year[0] : ''};${sum.volume || ''}${sum.issue ? '(' + sum.issue + ')' : ''}${sum.pages ? ':' + sum.pages : ''}`.replace(/\s+/g, ' ').trim();
}

// Resolve one slot from a given esearch term: fetch candidates, validate each against EVERY
// anti-fabrication invariant (summary, abstract, retracted, on-topic, grounded killer), and
// return the first title-match candidate (or a non-title backup). Mutates usedPmids + out.trace.
// Returns the chosen candidate or null. Never throws (caller wraps). Shared by A1/A2 and the
// A3 mechanism-hint cascade so all slots enforce identical invariants.
async function resolveSlotFromTerm(condition, slotName, term, retmax, usedPmids, out) {
  const pmids = await esearch(term, retmax);
  if (!pmids.length) { out.trace.push({ slot: slotName, term, note: 'no_search_hits' }); return null; }
  const summaries = await esummaryBatch(pmids);
  // Prefer the first VALID candidate whose TITLE matches the condition (high-precision
  // appropriateness signal per the 2026-06-02 audit). Remember the first valid NON-title
  // candidate as a backup and use it only if no title-match candidate validates — never hard
  // filter, since ~20-30% of good anchors (broad guidelines, anatomy-named mechanism) lack a
  // title token. Candidates arrive in NCBI relevance order.
  let picked = null, backup = null;
  for (const pmid of pmids) {
    if (usedPmids.has(String(pmid))) { continue; } // already used for another slot
    const sum = summaries[pmid];
    if (!sum || !sum.title || !sum.source) { out.trace.push({ slot: slotName, pmid, reject: 'no_summary' }); continue; }
    let abstract = '', isRetracted = false;
    try { const x = parseAbstractXml(await efetchAbstractXml(pmid)); abstract = x.abstract; isRetracted = x.isRetracted; }
    catch (e) { out.trace.push({ slot: slotName, pmid, reject: 'efetch_error', error: e.message }); continue; }
    if (isRetracted) { out.trace.push({ slot: slotName, pmid, reject: 'retracted' }); continue; }
    if (!abstract || abstract.length < 80) { out.trace.push({ slot: slotName, pmid, reject: 'no_abstract' }); continue; }
    if (!isOnTopic(condition, sum.title, abstract)) { out.trace.push({ slot: slotName, pmid, reject: 'off_topic' }); continue; }
    const killer = extractKiller(abstract);
    if (!killer || abstract.indexOf(killer) === -1) { out.trace.push({ slot: slotName, pmid, reject: 'no_grounded_stat' }); continue; }
    const cand = {
      slot: slotName, slot_label: SLOT[slotName].label, pmid: String(pmid),
      title: sum.title, journal: sum.source, year: (sum.pubdate || '').match(/\d{4}/) ? (sum.pubdate.match(/\d{4}/))[0] : '',
      full_citation: buildCitation(sum), killer_finding: killer, source: 'fallback_ncbi_grounded',
      title_match: titleMatches(condition, sum.title),
    };
    if (cand.title_match) { picked = cand; out.trace.push({ slot: slotName, pmid: String(pmid), accept: 'title_match' }); break; }
    if (!backup) { backup = cand; out.trace.push({ slot: slotName, pmid: String(pmid), valid: 'non_title_backup' }); }
  }
  const chosen = picked || backup;
  if (chosen && !picked) out.trace.push({ slot: slotName, pmid: chosen.pmid, accept: 'non_title_fallback' });
  return chosen;
}

// ── main: retrieve up to one grounded anchor per slot ──
// Returns { condition, status, anchors:[...], trace:[...], retrieved_at }. Never throws.
// opts.mechanismHints (optional string[]) drives the A3 mechanism sub-query cascade (C2.iii):
//   each hint is ANDed with the condition + the MECHANISM terms and tried in order until a
//   verified anchor is found, falling back to the generic mechanism query last.
async function retrieveGroundedAnchors(condition, opts = {}) {
  const out = { condition, status: 'no_data', anchors: [], trace: [], retrieved_at: new Date().toISOString() };
  if (!condition || !String(condition).trim()) { out.status = 'invalid_condition'; return out; }
  let anyNetwork = false, anyError = false;
  const usedPmids = new Set(); // a paper may fill only one slot
  const mechanismHints = Array.isArray(opts.mechanismHints)
    ? opts.mechanismHints.map((h) => String(h || '').trim()).filter(Boolean)
    : [];

  for (const slotName of ['A1', 'A2', 'A3']) {
    try {
      const retmax = slotRetmax(slotName);
      let chosen = null;
      if (slotName === 'A3') {
        // Ordered per-mechanism sub-query cascade (C2.iii): try each hint, then the generic
        // mechanism query, accumulating verified anchors. First verified anchor wins.
        const terms = [
          ...mechanismHints.map((h) => `${condition} AND ${h} AND ${SLOT.A3.terms}`),
          `${condition} AND ${SLOT.A3.terms}`,
        ];
        for (const term of terms) {
          chosen = await resolveSlotFromTerm(condition, slotName, term, retmax, usedPmids, out);
          anyNetwork = true;
          if (chosen) break;
        }
      } else {
        chosen = await resolveSlotFromTerm(condition, slotName, `${condition} AND ${SLOT[slotName].terms}`, retmax, usedPmids, out);
        anyNetwork = true;
      }
      if (chosen) { out.anchors.push(chosen); usedPmids.add(chosen.pmid); }
    } catch (e) {
      anyError = true;
      out.trace.push({ slot: slotName, error: e.message });
    }
  }

  if (out.anchors.length >= 1) out.status = 'grounded';
  else if (anyError && !anyNetwork) out.status = 'network_error';
  else out.status = 'no_data';
  return out;
}

// verifyPmidById(pmid, claimedCondition) (C2.v) — re-fetch a SINGLE known PMID and re-run the
// SAME grounded validation (esummary metadata + efetch abstract + verbatim killer-finding
// substring + retracted + on-topic). For Feature B apply-time re-verification of a citation a
// physician/drafter already selected. Never throws — returns { verified:false, ... } on any
// failure. PMID is never generated; it is the input and is re-confirmed against NCBI.
async function verifyPmidById(pmid, claimedCondition) {
  const cleanPmid = String(pmid || '').replace(/[^0-9]/g, '');
  const base = { verified: false, pmid: cleanPmid, title: '', journal: '', year: '', killer_finding: '' };
  if (!cleanPmid) return Object.assign(base, { reason: 'invalid_pmid' });
  try {
    const summaries = await esummaryBatch([cleanPmid]);
    const sum = summaries[cleanPmid];
    if (!sum || !sum.title || !sum.source) return Object.assign(base, { reason: 'no_summary' });
    let abstract = '', isRetracted = false;
    try { const x = parseAbstractXml(await efetchAbstractXml(cleanPmid)); abstract = x.abstract; isRetracted = x.isRetracted; }
    catch (e) { return Object.assign(base, { reason: 'efetch_error', error: e.message }); }
    if (isRetracted) return Object.assign(base, { reason: 'retracted' });
    if (!abstract || abstract.length < 80) return Object.assign(base, { reason: 'no_abstract' });
    // On-topic gate only when a condition is supplied (the caller may verify a bare PMID).
    if (claimedCondition && String(claimedCondition).trim() && !isOnTopic(claimedCondition, sum.title, abstract)) {
      return Object.assign(base, { reason: 'off_topic', title: sum.title, journal: sum.source });
    }
    const killer = extractKiller(abstract);
    if (!killer || abstract.indexOf(killer) === -1) {
      return Object.assign(base, { reason: 'no_grounded_stat', title: sum.title, journal: sum.source });
    }
    return {
      verified: true, pmid: cleanPmid, title: sum.title, journal: sum.source,
      year: (sum.pubdate || '').match(/\d{4}/) ? (sum.pubdate.match(/\d{4}/))[0] : '',
      killer_finding: killer,
      // full_citation = the HOUSE-FORMAT reference line (Author. Title. Journal. Year;Vol(Issue):Pages),
      // built from the SAME esummary metadata retrieveGroundedAnchors uses, so the Citation Enricher can
      // insert a §VIII reference that matches the existing numbered entries exactly (Spring §VIII
      // formatting fix, 2026-06-25). Grounded: every field is from NCBI esummary, never a model.
      // NOTE: re-vendor parity — the FRN source app/services/citationFallback.js needs this same line.
      full_citation: buildCitation(sum),
    };
  } catch (e) {
    return Object.assign(base, { reason: 'verify_error', error: e.message });
  }
}

// Render grounded anchors into a key_excerpts.md-format string the drafter consumes verbatim.
function renderExcerptsMd(condition, result) {
  let md = `# ${condition} — GROUNDED FALLBACK CITATIONS (auto-retrieved ${result.retrieved_at})\n\n`;
  md += `**⚠️ FALLBACK SOURCE:** No curated library folder exists for "${condition}". The citations below were retrieved live from NCBI PubMed (E-utilities) and validated: real PMID, on-topic, non-retracted, killer finding is a verbatim abstract sentence. Use them exactly as written. Do NOT add citations from memory.\n\n`;
  if (!result.anchors.length) {
    md += `**No grounded citations could be retrieved (status: ${result.status}).** Draft on the chart facts, the in-service event, the regulation, and sound clinical mechanism reasoning. Do NOT fabricate any citation. Flag for physician citation backfill.\n`;
    return md;
  }
  for (const a of result.anchors) {
    md += `## ${a.slot} ${a.slot_label} — ${a.full_citation}\n`;
    md += `**PMID:** ${a.pmid} (grounded via NCBI E-utilities, fallback retrieval)\n`;
    md += `**Killer finding (verbatim from abstract):** ${a.killer_finding}\n`;
    md += `**Quotable conclusion:** ${a.killer_finding}\n\n`;
  }
  md += `**Drafter note:** these are the only verified citations available for this claim. If a needed anchor is missing, develop that point via mechanism reasoning and the regulation rather than inventing a citation.\n`;
  return md;
}

module.exports = {
  retrieveGroundedAnchors, renderExcerptsMd, verifyPmidById, normalizeCondition,
  _extractKiller: extractKiller, _isOnTopic: isOnTopic, _condTokens: condTokens,
};
